mapper.select:
SELECT pr.*, o.user_id, o.store_id, u.nickname, u.phone
FROM payment_record pr
LEFT JOIN `order` o ON o.order_no = pr.order_no AND o.deleted = 0
LEFT JOIN `user` u ON u.id = o.user_id AND u.deleted = 0
WHERE pr.deleted = 0
AND o.store_id = #{storeId}
AND pr.order_no = #{orderNo}
AND pr.trade_state = #{tradeState}
ORDER BY pr.id DESC LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM payment_record pr
LEFT JOIN `order` o ON o.order_no = pr.order_no AND o.deleted = 0
WHERE pr.deleted = 0
AND o.store_id = #{storeId}
AND pr.order_no = #{orderNo}
AND pr.trade_state = #{tradeState}
